"use strict";(self.webpackChunkmd_vuepress=self.webpackChunkmd_vuepress||[]).push([[899],{1716:(n,e,s)=>{s.r(e),s.d(e,{data:()=>a});const a={key:"v-4581920c",path:"/react/react-render.html",title:"React 的渲染流程",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"🌟 一句话概括 React 渲染流程：",slug:"🌟-一句话概括-react-渲染流程",children:[]},{level:2,title:"一、整体架构图（文字版）",slug:"一、整体架构图-文字版",children:[]},{level:2,title:"二、分步详解（结合源码逻辑）",slug:"二、分步详解-结合源码逻辑",children:[{level:3,title:"步骤 1️⃣：初始化根容器（createRoot）",slug:"步骤-1️⃣-初始化根容器-createroot",children:[]},{level:3,title:"步骤 2️⃣：调度更新（Scheduler 介入）",slug:"步骤-2️⃣-调度更新-scheduler-介入",children:[]},{level:3,title:"步骤 3️⃣：工作循环（workLoop）",slug:"步骤-3️⃣-工作循环-workloop",children:[]},{level:3,title:"步骤 4️⃣：performUnitOfWork → beginWork（向下）",slug:"步骤-4️⃣-performunitofwork-→-beginwork-向下",children:[]},{level:3,title:"步骤 5️⃣：completeUnitOfWork → completeWork（向上）",slug:"步骤-5️⃣-completeunitofwork-→-completework-向上",children:[]},{level:3,title:"步骤 6️⃣：提交阶段（Commit Phase）",slug:"步骤-6️⃣-提交阶段-commit-phase",children:[]},{level:3,title:"步骤 7️⃣：双缓冲切换（Double Buffering）",slug:"步骤-7️⃣-双缓冲切换-double-buffering",children:[]}]},{level:2,title:"三、关键数据结构回顾",slug:"三、关键数据结构回顾",children:[{level:3,title:"Fiber 节点核心字段",slug:"fiber-节点核心字段",children:[]},{level:3,title:"Effect 链表",slug:"effect-链表",children:[]}]},{level:2,title:"四、结合你的项目场景（my-ticket-agent）",slug:"四、结合你的项目场景-my-ticket-agent",children:[]},{level:2,title:"五、关键源码文件速查（React 18）",slug:"五、关键源码文件速查-react-18",children:[]},{level:2,title:"✅ 总结：React 渲染三阶段",slug:"✅-总结-react-渲染三阶段",children:[]}],git:{updatedTime:1780969118e3},filePathRelative:"react/react-render.md"}},8017:(n,e,s)=>{s.r(e),s.d(e,{default:()=>o});const a=(0,s(6252).uE)('<h1 id="react-的渲染流程" tabindex="-1"><a class="header-anchor" href="#react-的渲染流程" aria-hidden="true">#</a> React 的渲染流程</h1><p>现在我们从 <strong>React 源码角度</strong>（以 <strong>React 18+</strong> 为主，基于 <code>react-reconciler</code> 和 <code>react-dom</code>）系统性地讲解 <strong>React 从 <code>createRoot().render(&lt;App /&gt;)</code> 到真实 DOM 渲染完成的完整流程</strong>。</p><p>我们将聚焦 <strong>Fiber 架构下的核心机制</strong>，涵盖：初始化、调度、渲染（render 阶段）、提交（commit 阶段）、副作用处理等，同时说明关键函数（如 <code>beginWork</code>、<code>completeWork</code>、<code>commitRoot</code>）的作用和调用时机。</p><hr><h2 id="🌟-一句话概括-react-渲染流程" tabindex="-1"><a class="header-anchor" href="#🌟-一句话概括-react-渲染流程" aria-hidden="true">#</a> 🌟 一句话概括 React 渲染流程：</h2><blockquote><p><strong>触发更新 → 创建 Fiber 树（workInProgress）→ 协调（reconcile）生成 Effect 链表 → 提交（commit）更新真实 DOM → 执行生命周期/副作用</strong></p></blockquote><p>整个过程分为两个大阶段：</p><ul><li><strong>Render Phase</strong>（可中断、异步，构建 Fiber 树 + Effect list）</li><li><strong>Commit Phase</strong>（不可中断、同步，操作 DOM + 执行副作用）</li></ul><hr><h2 id="一、整体架构图-文字版" tabindex="-1"><a class="header-anchor" href="#一、整体架构图-文字版" aria-hidden="true">#</a> 一、整体架构图（文字版）</h2><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>[createRoot().render(&lt;App /&gt;)]\n         ↓\nscheduleUpdateOnFiber(fiber, update)  ← 触发更新\n         ↓\nensureRootIsScheduled(root)           ← 调度器介入\n         ↓\nworkLoopConcurrent() 或 workLoopSync()\n         │\n         ├─▶ performUnitOfWork(fiber)\n         │        ↓\n         │    beginWork(fiber)         ← 向下协调，处理子节点\n         │        ↓\n         │    reconcileChildren()      ← diff 新旧 children，创建子 Fiber\n         │\n         └─▶ completeUnitOfWork(fiber)\n                  ↓\n              completeWork(fiber)      ← 向上收尾，收集 DOM 副作用\n                  ↓\n              构建 effectList（链表：nextEffect）\n         ↓\n所有 Fiber 处理完？ → 是\n         ↓\ncommitRoot(root)\n         ↓\ncommitMutationEffects(root)        ← 执行 DOM 插入/更新/删除\n         ↓\ncommitLayoutEffects(root)          ← 执行 useLayoutEffect / componentDidMount\n         ↓\nschedulePassiveEffects()           ← 异步调度 useEffect（微任务）\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br></div></div><hr><h2 id="二、分步详解-结合源码逻辑" tabindex="-1"><a class="header-anchor" href="#二、分步详解-结合源码逻辑" aria-hidden="true">#</a> 二、分步详解（结合源码逻辑）</h2><h3 id="步骤-1️⃣-初始化根容器-createroot" tabindex="-1"><a class="header-anchor" href="#步骤-1️⃣-初始化根容器-createroot" aria-hidden="true">#</a> 步骤 1️⃣：初始化根容器（createRoot）</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">const</span> root <span class="token operator">=</span> ReactDOM<span class="token punctuation">.</span><span class="token function">createRoot</span><span class="token punctuation">(</span>container<span class="token punctuation">)</span>\nroot<span class="token punctuation">.</span><span class="token function">render</span><span class="token punctuation">(</span><span class="token operator">&lt;</span>App <span class="token operator">/</span><span class="token operator">&gt;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>源码位置</strong>：<code>packages/react-dom/src/client/ReactDOMRoot.js</code></p><ul><li>创建 <strong>FiberRoot</strong>（全局根对象，包含 current Fiber 树）</li><li>创建 <strong>root Fiber</strong>（type = HostRoot，tag = HostRoot）</li><li>调用 <code>updateContainer(&lt;App /&gt;, root)</code> → 创建一个 <strong>Update 对象</strong> 并入队</li></ul><blockquote><p>✅ <code>FiberRoot</code> 是 React 的“调度单元”，<code>root.current</code> 指向当前显示的 Fiber 树。</p></blockquote><hr><h3 id="步骤-2️⃣-调度更新-scheduler-介入" tabindex="-1"><a class="header-anchor" href="#步骤-2️⃣-调度更新-scheduler-介入" aria-hidden="true">#</a> 步骤 2️⃣：调度更新（Scheduler 介入）</h3><p><strong>函数</strong>：<code>scheduleUpdateOnFiber(fiber, update)</code> → <code>ensureRootIsScheduled(root)</code></p><ul><li>判断是否并发模式（<code>createRoot</code>）→ 使用 <code>Scheduler</code> 调度</li><li>调用 <code>scheduleCallback(priorityLevel, workLoop)</code><ul><li>底层用 <code>MessageChannel</code> 模拟 <code>requestIdleCallback</code></li><li>把 <code>workLoopConcurrent</code> 放入微任务/宏任务队列</li></ul></li></ul><blockquote><p>💡 此时 <strong>还没有开始渲染</strong>，只是“安排了一个任务”。</p></blockquote><hr><h3 id="步骤-3️⃣-工作循环-workloop" tabindex="-1"><a class="header-anchor" href="#步骤-3️⃣-工作循环-workloop" aria-hidden="true">#</a> 步骤 3️⃣：工作循环（workLoop）</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">workLoopConcurrent</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">while</span> <span class="token punctuation">(</span>workInProgress <span class="token operator">!==</span> <span class="token keyword">null</span> <span class="token operator">&amp;&amp;</span> <span class="token operator">!</span><span class="token function">shouldYield</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token function">performUnitOfWork</span><span class="token punctuation">(</span>workInProgress<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><ul><li><code>workInProgress</code>：当前正在构建的 Fiber 节点（WIP 树）</li><li><code>shouldYield()</code>：检查是否该让出主线程（基于 5ms 时间片）</li></ul><hr><h3 id="步骤-4️⃣-performunitofwork-→-beginwork-向下" tabindex="-1"><a class="header-anchor" href="#步骤-4️⃣-performunitofwork-→-beginwork-向下" aria-hidden="true">#</a> 步骤 4️⃣：performUnitOfWork → beginWork（向下）</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">performUnitOfWork</span><span class="token punctuation">(</span><span class="token parameter"><span class="token literal-property property">unitOfWork</span><span class="token operator">:</span> Fiber</span><span class="token punctuation">)</span><span class="token operator">:</span> Fiber <span class="token operator">|</span> <span class="token keyword">null</span> <span class="token punctuation">{</span>\n  <span class="token keyword">const</span> current <span class="token operator">=</span> unitOfWork<span class="token punctuation">.</span>alternate\n  <span class="token keyword">let</span> next <span class="token operator">=</span> <span class="token function">beginWork</span><span class="token punctuation">(</span>current<span class="token punctuation">,</span> unitOfWork<span class="token punctuation">,</span> subtreeRenderLanes<span class="token punctuation">)</span>\n\n  <span class="token keyword">if</span> <span class="token punctuation">(</span>next <span class="token operator">===</span> <span class="token keyword">null</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token comment">// 没有子节点 → 完成当前节点</span>\n    <span class="token function">completeUnitOfWork</span><span class="token punctuation">(</span>unitOfWork<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n  <span class="token keyword">return</span> next <span class="token comment">// 返回 child，继续向下</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h4 id="🔍-beginwork-做了什么" tabindex="-1"><a class="header-anchor" href="#🔍-beginwork-做了什么" aria-hidden="true">#</a> 🔍 <code>beginWork</code> 做了什么？</h4><p><strong>源码位置</strong>：<code>packages/react-reconciler/src/ReactFiberBeginWork.js</code></p><ul><li>根据 <code>fiber.tag</code> 类型处理： <ul><li><code>FunctionComponent</code> → 调用 <code>renderWithHooks()</code> → 执行你的函数组件</li><li><code>HostComponent</code>（如 <code>div</code>）→ 准备 props</li></ul></li><li>调用 <code>reconcileChildren(current, workInProgress, nextChildren)</code><ul><li><strong>核心 diff 逻辑</strong>：对比新旧 children，复用/创建/删除 Fiber</li><li>使用 key 优化（类似 Vue）</li><li>返回 <code>workInProgress.child</code></li></ul></li></ul><blockquote><p>✅ 此阶段 <strong>不操作 DOM</strong>，只构建新的 Fiber 树（WIP 树）。</p></blockquote><hr><h3 id="步骤-5️⃣-completeunitofwork-→-completework-向上" tabindex="-1"><a class="header-anchor" href="#步骤-5️⃣-completeunitofwork-→-completework-向上" aria-hidden="true">#</a> 步骤 5️⃣：completeUnitOfWork → completeWork（向上）</h3><p>当一个 Fiber 节点没有子节点（或子节点已处理完），开始回溯：</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">completeUnitOfWork</span><span class="token punctuation">(</span><span class="token parameter"><span class="token literal-property property">unitOfWork</span><span class="token operator">:</span> Fiber</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token keyword">void</span> <span class="token punctuation">{</span>\n  <span class="token keyword">let</span> completedWork <span class="token operator">=</span> unitOfWork<span class="token punctuation">;</span>\n  <span class="token keyword">do</span> <span class="token punctuation">{</span>\n    <span class="token keyword">const</span> current <span class="token operator">=</span> completedWork<span class="token punctuation">.</span>alternate<span class="token punctuation">;</span>\n    <span class="token keyword">const</span> returnFiber <span class="token operator">=</span> completedWork<span class="token punctuation">.</span>return<span class="token punctuation">;</span>\n    <span class="token function">completeWork</span><span class="token punctuation">(</span>current<span class="token punctuation">,</span> completedWork<span class="token punctuation">,</span> subtreeRenderLanes<span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n    <span class="token comment">// 构建 effect list（用于 commit 阶段）</span>\n    <span class="token keyword">const</span> next <span class="token operator">=</span> <span class="token comment">/* sibling or parent */</span><span class="token punctuation">;</span>\n    completedWork <span class="token operator">=</span> next<span class="token punctuation">;</span>\n  <span class="token punctuation">}</span> <span class="token keyword">while</span> <span class="token punctuation">(</span>completedWork <span class="token operator">!==</span> <span class="token keyword">null</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h4 id="🔍-completework-做了什么" tabindex="-1"><a class="header-anchor" href="#🔍-completework-做了什么" aria-hidden="true">#</a> 🔍 <code>completeWork</code> 做了什么？</h4><p><strong>源码位置</strong>：<code>packages/react-reconciler/src/ReactFiberCompleteWork.js</code></p><ul><li>对 <code>HostComponent</code>（如 <code>div</code>）： <ul><li>调用 <code>createInstance(type, props)</code> → <strong>创建 DOM 节点描述</strong>（非真实创建）</li><li>调用 <code>appendAllChildren(instance, completedWork)</code> → 把子 DOM 挂到自己</li><li>设置 <code>fiber.stateNode = instance</code></li></ul></li><li>标记副作用： <ul><li><code>Placement</code>（需要插入）</li><li><code>Update</code>（需要更新属性）</li><li><code>Deletion</code>（需要删除）</li></ul></li><li>构建 <code>effectList</code> 链表（通过 <code>nextEffect</code> 指针）</li></ul><blockquote><p>✅ 此阶段 <strong>收集所有 DOM 操作</strong>，但 <strong>仍未操作真实 DOM</strong>。</p></blockquote><hr><h3 id="步骤-6️⃣-提交阶段-commit-phase" tabindex="-1"><a class="header-anchor" href="#步骤-6️⃣-提交阶段-commit-phase" aria-hidden="true">#</a> 步骤 6️⃣：提交阶段（Commit Phase）</h3><p>当整棵 WIP 树构建完成，进入 <strong>不可中断的同步阶段</strong>：</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">commitRoot</span><span class="token punctuation">(</span><span class="token parameter">root</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token comment">// 1. before mutation（快照）</span>\n  <span class="token function">commitBeforeMutationEffects</span><span class="token punctuation">(</span>root<span class="token punctuation">)</span>\n\n  <span class="token comment">// 2. mutation（操作 DOM）</span>\n  <span class="token function">commitMutationEffects</span><span class="token punctuation">(</span>root<span class="token punctuation">,</span> rootFiber<span class="token punctuation">,</span> lanes<span class="token punctuation">)</span>\n\n  <span class="token comment">// 3. layout（同步副作用）</span>\n  <span class="token function">commitLayoutEffects</span><span class="token punctuation">(</span>root<span class="token punctuation">,</span> lanes<span class="token punctuation">)</span>\n\n  <span class="token comment">// 4. 调度 passive effects（useEffect）</span>\n  <span class="token function">schedulePassiveEffects</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h4 id="🧨-6-1-commitmutationeffects-真实-dom-操作" tabindex="-1"><a class="header-anchor" href="#🧨-6-1-commitmutationeffects-真实-dom-操作" aria-hidden="true">#</a> 🧨 6.1 commitMutationEffects（真实 DOM 操作）</h4><ul><li>遍历 <code>effectList</code></li><li>根据 <code>effectTag</code> 执行： <ul><li><code>Placement</code> → <code>parent.appendChild(child.stateNode)</code></li><li><code>Update</code> → <code>updateDOMProperties(oldProps, newProps)</code></li><li><code>Deletion</code> → <code>parent.removeChild(child.stateNode)</code></li></ul></li></ul><h4 id="🧪-6-2-commitlayouteffects" tabindex="-1"><a class="header-anchor" href="#🧪-6-2-commitlayouteffects" aria-hidden="true">#</a> 🧪 6.2 commitLayoutEffects</h4><ul><li>执行 <code>useLayoutEffect</code> 回调</li><li>执行 Class 组件的 <code>componentDidMount</code> / <code>componentDidUpdate</code></li><li><strong>此时 DOM 已更新，可读取布局</strong></li></ul><h4 id="⏳-6-3-schedulepassiveeffects" tabindex="-1"><a class="header-anchor" href="#⏳-6-3-schedulepassiveeffects" aria-hidden="true">#</a> ⏳ 6.3 schedulePassiveEffects</h4><ul><li>用 <code>Scheduler.scheduleCallback(NormalPriority, flushPassiveEffects)</code></li><li>在 <strong>下一个宏任务</strong>（或微任务）中执行 <code>useEffect</code></li><li><strong>避免阻塞 paint</strong></li></ul><hr><h3 id="步骤-7️⃣-双缓冲切换-double-buffering" tabindex="-1"><a class="header-anchor" href="#步骤-7️⃣-双缓冲切换-double-buffering" aria-hidden="true">#</a> 步骤 7️⃣：双缓冲切换（Double Buffering）</h3><ul><li>提交完成后：<div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>root<span class="token punctuation">.</span>current <span class="token operator">=</span> finishedWork <span class="token comment">// WIP 树变成 current 树</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div></li><li>下次更新时，新的 WIP 树会复用 <code>current.alternate</code></li></ul><blockquote><p>✅ 避免内存抖动，高效复用 Fiber 节点。</p></blockquote><hr><h2 id="三、关键数据结构回顾" tabindex="-1"><a class="header-anchor" href="#三、关键数据结构回顾" aria-hidden="true">#</a> 三、关键数据结构回顾</h2><h3 id="fiber-节点核心字段" tabindex="-1"><a class="header-anchor" href="#fiber-节点核心字段" aria-hidden="true">#</a> Fiber 节点核心字段</h3><div class="language-typescript ext-ts line-numbers-mode"><pre class="language-typescript"><code><span class="token keyword">interface</span> <span class="token class-name">Fiber</span> <span class="token punctuation">{</span>\n  tag<span class="token operator">:</span> WorkTag <span class="token comment">// FunctionComponent, HostComponent...</span>\n  type<span class="token operator">:</span> <span class="token builtin">any</span> <span class="token comment">// 组件类型或 &#39;div&#39;</span>\n  stateNode<span class="token operator">:</span> <span class="token builtin">any</span> <span class="token comment">// 真实 DOM 或组件实例</span>\n  <span class="token keyword">return</span><span class="token operator">:</span> Fiber <span class="token operator">|</span> <span class="token keyword">null</span> <span class="token comment">// 父</span>\n  child<span class="token operator">:</span> Fiber <span class="token operator">|</span> <span class="token keyword">null</span> <span class="token comment">// 第一个子</span>\n  sibling<span class="token operator">:</span> Fiber <span class="token operator">|</span> <span class="token keyword">null</span> <span class="token comment">// 下一个兄弟</span>\n  alternate<span class="token operator">:</span> Fiber <span class="token operator">|</span> <span class="token keyword">null</span> <span class="token comment">// 双缓冲指针</span>\n  effectTag<span class="token operator">:</span> <span class="token builtin">number</span> <span class="token comment">// Placement | Update | Deletion</span>\n  nextEffect<span class="token operator">:</span> Fiber <span class="token operator">|</span> <span class="token keyword">null</span> <span class="token comment">// Effect 链表</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h3 id="effect-链表" tabindex="-1"><a class="header-anchor" href="#effect-链表" aria-hidden="true">#</a> Effect 链表</h3><ul><li>所有有副作用的 Fiber 节点通过 <code>nextEffect</code> 串成单链表</li><li>commit 阶段只需遍历该链表，无需遍历整棵树</li></ul><hr><h2 id="四、结合你的项目场景-my-ticket-agent" tabindex="-1"><a class="header-anchor" href="#四、结合你的项目场景-my-ticket-agent" aria-hidden="true">#</a> 四、结合你的项目场景（my-ticket-agent）</h2><p>你在渲染动态表单：</p><div class="language-tsx ext-tsx line-numbers-mode"><pre class="language-tsx"><code><span class="token punctuation">{</span>\n  fields<span class="token punctuation">.</span><span class="token function">map</span><span class="token punctuation">(</span><span class="token punctuation">(</span>f<span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">TicketField</span></span> <span class="token attr-name">key</span><span class="token script language-javascript"><span class="token script-punctuation punctuation">=</span><span class="token punctuation">{</span>f<span class="token punctuation">.</span>id<span class="token punctuation">}</span></span> <span class="token attr-name">config</span><span class="token script language-javascript"><span class="token script-punctuation punctuation">=</span><span class="token punctuation">{</span>f<span class="token punctuation">}</span></span> <span class="token punctuation">/&gt;</span></span><span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ol><li>当 <code>fields</code> 更新 → 触发 <code>setState</code></li><li>React 进入 <code>beginWork</code> → 执行你的组件函数 → 得到新 children</li><li><code>reconcileChildren</code> 对比新旧 <code>fields</code>： <ul><li>复用已有 <code>&lt;TicketField&gt;</code> Fiber（靠 key）</li><li>标记新增/删除</li></ul></li><li><code>completeWork</code> 为每个字段收集 DOM 操作</li><li><code>commitMutationEffects</code> 批量更新 DOM</li><li><code>useEffect</code> 最后执行（可用于日志/埋点）</li></ol><blockquote><p>💡 因为 React <strong>不知道具体哪变了</strong>，所以默认会重新执行整个组件函数（除非 <code>memo</code> 优化）。</p></blockquote><hr><h2 id="五、关键源码文件速查-react-18" tabindex="-1"><a class="header-anchor" href="#五、关键源码文件速查-react-18" aria-hidden="true">#</a> 五、关键源码文件速查（React 18）</h2><table><thead><tr><th>功能</th><th>源码路径</th></tr></thead><tbody><tr><td>Fiber 工作循环</td><td><code>react-reconciler/src/ReactFiberWorkLoop.js</code></td></tr><tr><td>beginWork</td><td><code>ReactFiberBeginWork.js</code></td></tr><tr><td>completeWork</td><td><code>ReactFiberCompleteWork.js</code></td></tr><tr><td>commit 阶段</td><td><code>ReactFiberCommitWork.js</code></td></tr><tr><td>调度器</td><td><code>scheduler/src/Scheduler.js</code></td></tr><tr><td>React DOM 入口</td><td><code>react-dom/src/client/ReactDOMRoot.js</code></td></tr></tbody></table><hr><h2 id="✅-总结-react-渲染三阶段" tabindex="-1"><a class="header-anchor" href="#✅-总结-react-渲染三阶段" aria-hidden="true">#</a> ✅ 总结：React 渲染三阶段</h2><table><thead><tr><th>阶段</th><th>是否可中断</th><th>主要工作</th><th>关键函数</th></tr></thead><tbody><tr><td><strong>Render</strong></td><td>✅</td><td>构建 Fiber 树、diff、收集 effect</td><td><code>beginWork</code>, <code>completeWork</code></td></tr><tr><td><strong>Pre-commit</strong></td><td>❌</td><td>快照（getSnapshotBeforeUpdate）</td><td><code>commitBeforeMutationEffects</code></td></tr><tr><td><strong>Commit</strong></td><td>❌</td><td>操作 DOM、执行副作用</td><td><code>commitMutationEffects</code>, <code>commitLayoutEffects</code></td></tr></tbody></table><hr><p>如果你希望，我可以：</p><ul><li>提供一个 <strong>极简 React Fiber 模拟器</strong>（&lt; 100 行 JS，演示 beginWork/completeWork）</li><li>对比 <strong>React 和 Vue 在动态表单更新时的性能差异</strong></li><li>或深入讲解 <strong>并发模式下的 Suspense / Transition 如何影响此流程</strong></li></ul>',77),t={},o=(0,s(3744).Z)(t,[["render",function(n,e){return a}]])}}]);